def token_f1(cand, span):
    a=set(tokenize(cand))
    b=set(tokenize(span))
    inter=len(a & b)
    if len(a)==0 or len(b)==0:
        return 0.0, 0.0, 0.0
    precision=inter/len(a)
    recall=inter/len(b)
    if precision+recall==0: f1=0.0
    else: f1=2*precision*recall/(precision+recall)
    return precision, recall, f1, inter, len(a), len(b)

